### Step 5: Seek Operations
```rust
impl AsyncSeek for File {
    fn poll_seek(
        self: Pin<&mut Self>,
        cx: &mut Context<'_>,
        pos: SeekFrom,
    ) -> Poll<io::Result<u64>> {
        // Async seek
    }
}

impl File {
    /// Seek from start
    pub async fn seek(&mut self, pos: SeekFrom) -> io::Result<u64>;

    /// Get current position
    pub async fn stream_position(&mut self) -> io::Result<u64> {
        self.seek(SeekFrom::Current(0)).await
    }

    /// Rewind to start
    pub async fn rewind(&mut self) -> io::Result<()> {
        self.seek(SeekFrom::Start(0)).await?;
        Ok(())
    }
}
```

### Step 6: Metadata Operations
```rust
impl File {
    /// Get metadata for this file
    pub async fn metadata(&self) -> io::Result<Metadata>;

    /// Set file length
    pub async fn set_len(&self, size: u64) -> io::Result<()>;

    /// Try to clone the file handle
    pub async fn try_clone(&self) -> io::Result<File>;

    /// Set permissions
    pub async fn set_permissions(&self, perm: Permissions) -> io::Result<()>;
}
```

## Platform Strategy
- **Linux**: Use io_uring for true async I/O when available
- **Other**: Fall back to spawn_blocking with thread pool

## Cancel-Safety
- Read: cancel discards partial data (acceptable)
- Write: two-phase with WritePermit for critical writes
- Seek: atomically completes before cancellation observed
- Metadata: atomically completes

## Testing

### Unit Tests
```rust
#[tokio::test]
async fn test_file_create_write_read() {
    let dir = tempdir().unwrap();
    let path = dir.path().join("test.txt");

    // Create and write
    let mut file = File::create(&path).await.unwrap();
    file.write_all(b"hello world").await.unwrap();
    file.sync_all().await.unwrap();
    drop(file);

    // Read back
    let mut file = File::open(&path).await.unwrap();
    let mut contents = String::new();
    file.read_to_string(&mut contents).await.unwrap();
    assert_eq\!(contents, "hello world");
}

#[tokio::test]
async fn test_file_seek() {
    let dir = tempdir().unwrap();
    let path = dir.path().join("test.txt");

    let mut file = File::create(&path).await.unwrap();
    file.write_all(b"0123456789").await.unwrap();

    file.seek(SeekFrom::Start(5)).await.unwrap();
    let mut buf = [0u8; 5];
    file.read_exact(&mut buf).await.unwrap();
    assert_eq\!(&buf, b"56789");
}

#[tokio::test]
async fn test_open_options() {
    let dir = tempdir().unwrap();
    let path = dir.path().join("test.txt");

    // create_new should fail if file exists
    File::create(&path).await.unwrap();

    let result = File::options()
        .write(true)
        .create_new(true)
        .open(&path)
        .await;
    assert\!(result.is_err());
}

#[tokio::test]
async fn test_cancel_during_read() {
    // Test that cancellation during read is handled cleanly
    let dir = tempdir().unwrap();
    let path = dir.path().join("test.txt");

    // Create large file
    let mut file = File::create(&path).await.unwrap();
    file.write_all(&vec\![0u8; 1_000_000]).await.unwrap();
    drop(file);

    let mut file = File::open(&path).await.unwrap();
    let mut buf = vec\![0u8; 1_000_000];

    // Cancel the read (should not panic or leak)
    let read_fut = file.read_exact(&mut buf);
    let timeout_fut = sleep(Duration::from_nanos(1));

    select\! {
        _ = read_fut => {}
        _ = timeout_fut => {} // Cancelled
    }
}
```

### E2E Tests
```rust
#[test]
fn e2e_file_operations() {
    // Test complete file lifecycle with logging
    setup_test_logging();

    let rt = LabRuntime::new();
    rt.block_on(async {
        info\!("Starting file operations E2E test");

        let temp = tempdir().unwrap();
        let path = temp.path().join("e2e_test.txt");

        // Phase 1: Create
        info\!(path = ?path, "Creating file");
        let mut file = File::create(&path).await
            .expect("Failed to create file");
        info\!("File created successfully");

        // Phase 2: Write
        let data = b"E2E test data with multiple lines\nLine 2\nLine 3\n";
        info\!(bytes = data.len(), "Writing data");
        file.write_all(data).await.expect("Write failed");
        file.sync_all().await.expect("Sync failed");
        info\!("Write completed and synced");
        drop(file);

        // Phase 3: Read and verify
        info\!("Opening file for reading");
        let mut file = File::open(&path).await.expect("Open failed");
        let mut contents = Vec::new();
        let n = file.read_to_end(&mut contents).await.expect("Read failed");
        info\!(bytes = n, "Read completed");
        assert_eq\!(&contents, data);
        info\!("Data verified");

        // Phase 4: Seek operations
        file.rewind().await.expect("Rewind failed");
        let pos = file.stream_position().await.expect("Position failed");
        assert_eq\!(pos, 0);
        info\!("Seek operations verified");

        info\!("E2E test completed successfully");
    });
}
```

## Logging Requirements
- DEBUG: All file open/close operations with paths
- DEBUG: Read/write sizes and offsets
- TRACE: Individual I/O operation timing
- ERROR: All I/O errors with context

