pub struct VirtualTcpListener {
    addr: SocketAddr,
    pending: VecDeque<(VirtualTcpStream, SocketAddr)>,
    // Lab runtime injects connections here
}

impl TcpListener for VirtualTcpListener {
    // Deterministic accept based on lab runtime schedule
}
```

