+        _addr: A,
+    ) -> impl std::future::Future<Output = io::Result<Self>> + Send {
+        async {
+            Err(io::Error::new(
+                io::ErrorKind::Unsupported,
+                "VirtualTcpStream::connect not supported; use VirtualTcpStream::pair()",
