+
+    fn peer_addr(&self) -> io::Result<SocketAddr> {
+        Ok(self.peer_addr)
+    }
+
+    fn local_addr(&self) -> io::Result<SocketAddr> {
+        Ok(self.local_addr)
+    }
+
+    fn shutdown(&self, how: Shutdown) -> io::Result<()> {
+        match how {
+            Shutdown::Read | Shutdown::Both => {
+                let mut half = self.read_half.lock().expect("lock poisoned");
+                half.closed = true;
+            }
+            Shutdown::Write => {}
+        }
+        match how {
+            Shutdown::Write | Shutdown::Both => {
+                let mut half = self.write_half.lock().expect("lock poisoned");
+                half.closed = true;
+                if let Some(waker) = half.waker.take() {
+                    waker.wake();
+                }
+            }
+            Shutdown::Read => {}
+        }
+        Ok(())
+    }
+
+    fn set_nodelay(&self, nodelay: bool) -> io::Result<()> {
+        // We can't mutate through &self without interior mutability,
+        // but for a virtual stream this is a no-op in practice.
+        let _ = nodelay;
+        Ok(())
+    }
